UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee work permit?","a":"No. Both ESDC (LMIA) and IRCC must approve where applicable."},{"q":"LMIA processing time?","a":"Varies—often 2–5 months for standard LMIA. Verify current ESDC service standards."},{"q":"LMIA-exempt categories?","a":"Includes ICT transfers, CUSMA professionals, PGWP, spousal open permits, etc.—verify exemption code."},{"q":"Can spouse work?","a":"Spouse may qualify for open work permit in some categories—verify current rules."},{"q":"Employer costs for LMIA?","a":"LMIA application fee CAD $1,000 per position; plus recruitment costs."},{"q":"Can apply at border?","a":"Some nationals may flagpole—verify eligibility and current policy."},{"q":"Work permit and PR pathway?","a":"Canadian experience may support CEC via Express Entry."},{"q":"What if LMIA refused?","a":"Review ESDC reasons; address recruitment or wage issues; reapply or explore exempt categories."},{"q":"What is Description for this service?","a":"Employer-specific or open work permit allowing foreign nationals to work in Canada. LMIA-required streams need positive LMIA from Employment and Social Development Canada (ESDC)."},{"q":"What is Eligible applicants for this service?","a":"Valid job offer from Canadian employer · LMIA or exempt category · Qualifying skills/experience · Medical/biometrics as required"},{"q":"What is LMIA process for this service?","a":"Employer must advertise, recruit, and demonstrate no Canadians available. ESDC LMIA adds weeks to months before IRCC application."},{"q":"Important note on LMIA process?","a":"Employer must advertise, recruit, and demonstrate no Canadians available. ESDC LMIA adds weeks to months before IRCC application."},{"q":"What is Key authority for this service?","a":"ESDC (LMIA) · IRCC (work permit)"},{"q":"What is After approval for this service?","a":"Work for specified employer (closed permit) or open category. Maintain status; employer compliance with LMIA conditions."},{"q":"Is Valid job offer / contract required?","a":"Valid job offer / contract is typically required."},{"q":"Is LMIA positive or exempt category confirmed required?","a":"Employer responsibility for LMIA"},{"q":"Is Qualifying work experience/education required?","a":"Qualifying work experience/education is typically required."},{"q":"Is Medical exam (if required) required?","a":"Assess whether Medical exam (if required) is satisfied for this case."},{"q":"Is Biometrics completed required?","a":"Assess whether Biometrics completed is satisfied for this case."},{"q":"Is No criminal inadmissibility required?","a":"No criminal inadmissibility is typically required."},{"q":"Is Employer compliance history required?","a":"Verify employer legitimacy"},{"q":"What is the Processing time?","a":"3–9m — LMIA + IRCC combined"},{"q":"What is the Government fee?","a":"CAD $155 — Worker fee + biometrics"},{"q":"What is the Our approval rate?","a":"86% — ~78% benchmark"},{"q":"What is the Required docs?","a":"15 — + LMIA if applicable"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & LMIA"},{"q":"What if the client has LMIA advertising deficiencies?","a":"Ensure ESDC advertising compliance before LMIA submit"},{"q":"Why is LMIA advertising deficiencies a problem?","a":"Employer did not meet recruitment advertising requirements."},{"q":"What if the client has Wrong NOC/ wage offer?","a":"Verify TEER and prevailing wage on Job Bank"},{"q":"Why is Wrong NOC/ wage offer a problem?","a":"Job classification or wage below median for region."}]'::jsonb
),
